import React, { useState, useEffect } from 'react';
import { ArrowUp } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const BackToTop = () => {
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const toggleVisibility = () => {
            if (window.pageYOffset > 300) {
                setIsVisible(true);
            } else {
                setIsVisible(false);
            }
        };

        window.addEventListener('scroll', toggleVisibility);
        return () => window.removeEventListener('scroll', toggleVisibility);
    }, []);

    const scrollToTop = () => {
        window.scrollTo({
            top: 0,
            behavior: 'smooth',
        });
    };

    return (
        <AnimatePresence>
            {isVisible && (
                <motion.button
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                    onClick={scrollToTop}
                    className="fixed bottom-8 right-8 z-40 bg-primary text-white p-3 rounded-full shadow-lg hover:bg-earth transition-colors"
                    aria-label="Back to top"
                >
                    <ArrowUp size={24} />
                </motion.button>
            )}
        </AnimatePresence>
    );
};

export default BackToTop;

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { Menu, X, Phone } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const Header = () => {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const location = useLocation();

    useEffect(() => {
        const handleScroll = () => setIsScrolled(window.scrollY > 50);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const navLinks = [
        { name: 'Home', path: '#home' },
        { name: 'About Us', path: '#about' },
        { name: 'Services', path: '#services' },
        { name: 'Products', path: '#products' },
        { name: 'Gallery', path: '#gallery' },
        { name: 'Contact', path: '#contact' },
    ];

    const isHome = location.pathname === '/';

    return (
        <header className={`header-main ${isScrolled || !isHome ? 'header-scrolled' : 'header-transparent'}`}>
            <div className="nav-container">

                {/* Logo */}
                <a href="#home" style={{ textDecoration: 'none' }}>
                    <div className="flex items-center gap-4 flex-nowrap">
                        <div className="circular-logo-container" style={{ width: '50px', height: '50px', border: '2px solid black' }}>
                            <img src="/logo.jpeg" alt="Logo" className="circular-logo-img" />
                        </div>
                        <span style={{
                            color: 'black',
                            fontWeight: 900,
                            letterSpacing: '0.1em',
                            fontSize: '1.2rem',
                            textTransform: 'uppercase'
                        }}>
                            Stonehouse
                        </span>
                    </div>
                </a>

                {/* Navigation */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '3rem' }}>
                    <nav className="nav-links-right hidden md:flex">
                        {navLinks.map((link) => (
                            <a
                                key={link.name}
                                href={link.path}
                                className="nav-link"
                                style={{ color: (isScrolled || !isHome) ? 'black' : 'white' }}
                            >
                                {link.name}
                            </a>
                        ))}
                    </nav>

                    <a href="#contact" className="cta-btn cta-primary no-underline" style={{ padding: '0.8rem 1.8rem', fontSize: '10px' }}>
                        <Phone size={12} style={{ marginRight: '8px' }} /> Get Quote
                    </a>

                    {/* Mobile Toggle */}
                    <button
                        className="mobile-toggle block md:hidden"
                        onClick={() => setIsOpen(!isOpen)}
                        style={{ background: 'none', border: 'none', color: (isScrolled || !isHome ? 'black' : 'white') }}
                    >
                        {isOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        style={{ background: 'white', position: 'absolute', top: '100%', left: 0, width: '100%', borderTop: '1px solid #eee' }}
                    >
                        <div className="flex flex-col p-8 gap-6 text-center">
                            {navLinks.map((link) => (
                                <a
                                    key={link.name}
                                    href={link.path}
                                    onClick={() => setIsOpen(false)}
                                    className="text-lg font-black no-underline text-black uppercase tracking-widest"
                                >
                                    {link.name}
                                </a>
                            ))}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </header>
    );
};

export default Header;

import React from 'react';
import { Link } from 'react-router-dom';
import { MoveRight } from 'lucide-react';
import { motion } from 'framer-motion';

const NextPage = ({ nextPath, nextName }) => {
    return (
        <section className="luxury-nav-section">
            <div className="container">
                <Link to={nextPath} className="luxury-nav-link">
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        className="luxury-shadow-box text-center"
                    >
                        <p className="text-xs uppercase font-medium tracking-[0.5em] text-muted mb-8 opacity-50">
                            The Next Chapter
                        </p>

                        <div className="flex flex-col items-center">
                            <h2 className="serif-heading">
                                {nextName}
                            </h2>

                            <div className="luxury-arrow-container">
                                <MoveRight size={48} strokeWidth={1} className="minimal-thin-arrow" />
                            </div>
                        </div>
                    </motion.div>
                </Link>
            </div>
        </section>
    );
};

export default NextPage;

import React from 'react';
import { motion } from 'framer-motion';
import { ArrowRight, Maximize2 } from 'lucide-react';

const ProductCard = ({ product }) => {
    return (
        <motion.div
            whileHover={{ y: -10 }}
            className="bg-surface rounded-2xl overflow-hidden shadow-md hover:shadow-2xl transition-all border border-gray-100 group h-full flex flex-col"
        >
            <div className="relative h-64 overflow-hidden">
                <img
                    src={product.image}
                    alt={product.name}
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                />

                {/* Visual indicator for lightbox */}
                <div className="absolute inset-0 bg-earth/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                    <div className="bg-white/90 p-3 rounded-full text-primary scale-50 group-hover:scale-100 transition-transform duration-300">
                        <Maximize2 size={24} />
                    </div>
                </div>

                <div className="absolute top-4 left-4">
                    <span className="px-3 py-1 bg-white/90 backdrop-blur-md rounded-full text-[10px] uppercase font-bold tracking-widest text-primary">
                        {product.tags?.[0] || 'Natural Stone'}
                    </span>
                </div>
            </div>

            <div className="p-8 flex flex-col flex-grow">
                <h3 className="text-2xl font-bold mb-3 group-hover:text-primary transition-colors">
                    {product.name}
                </h3>
                <p className="text-text-muted text-sm line-clamp-3 leading-relaxed mb-6">
                    {product.description}
                </p>
                <div className="mt-auto pt-4 flex items-center gap-2 font-bold text-primary group-hover:gap-4 transition-all">
                    View Details <ArrowRight size={18} />
                </div>
            </div>
        </motion.div>
    );
};

export default ProductCard;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Check } from 'lucide-react';

const ProductModal = ({ product, isOpen, onClose }) => {
    if (!product) return null;

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-earth/80 backdrop-blur-sm"
                    />

                    {/* Modal Content */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.9, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.9, y: 20 }}
                        className="relative bg-white w-full max-w-4xl max-h-[90vh] rounded-2xl overflow-hidden shadow-2xl flex flex-col md:flex-row z-10"
                    >
                        {/* Close Button */}
                        <button
                            onClick={onClose}
                            className="absolute top-4 right-4 z-20 bg-earth/10 hover:bg-earth/20 p-2 rounded-full transition-colors"
                        >
                            <X size={24} className="text-earth" />
                        </button>

                        {/* Image Section */}
                        <div className="md:w-1/2 h-64 md:h-auto overflow-hidden">
                            <img
                                src={product.image}
                                alt={product.name}
                                className="w-full h-full object-cover"
                            />
                        </div>

                        {/* Details Section */}
                        <div className="md:w-1/2 p-8 md:p-12 overflow-y-auto">
                            <h2 className="text-3xl font-bold mb-4">{product.name}</h2>
                            <div className="flex flex-wrap gap-2 mb-6">
                                {product.tags?.map(tag => (
                                    <span key={tag} className="px-3 py-1 bg-primary/10 text-primary text-xs font-bold uppercase tracking-widest rounded-full">
                                        {tag}
                                    </span>
                                ))}
                            </div>

                            <p className="text-text-muted text-lg leading-relaxed mb-8">
                                {product.description}
                            </p>

                            <div className="space-y-4 mb-10">
                                <h4 className="font-bold uppercase tracking-widest text-sm text-earth">Key Features</h4>
                                <ul className="space-y-3">
                                    <li className="flex items-center gap-3 text-text-muted">
                                        <Check size={18} className="text-primary" /> Natural Texture & Color
                                    </li>
                                    <li className="flex items-center gap-3 text-text-muted">
                                        <Check size={18} className="text-primary" /> Weather Resistant
                                    </li>
                                    <li className="flex items-center gap-3 text-text-muted">
                                        <Check size={18} className="text-primary" /> Low Maintenance
                                    </li>
                                </ul>
                            </div>

                            <button onClick={onClose} className="btn btn-primary w-full py-4 text-lg">
                                Close Details
                            </button>
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
};

export default ProductModal;

import React from 'react';
import * as LucideIcons from 'lucide-react';
import { motion } from 'framer-motion';

const ServiceCard = ({ service }) => {
    const Icon = LucideIcons[service.icon];

    return (
        <motion.div
            whileHover={{ scale: 1.05 }}
            className="bg-surface p-8 rounded-2xl shadow-sm border-l-4 border-primary hover:shadow-md transition-all"
        >
            <div className="w-12 h-12 bg-primary/10 rounded-lg flex items-center justify-center text-primary mb-6">
                <Icon size={24} />
            </div>
            <h3 className="text-xl font-bold mb-4">{service.title}</h3>
            <p className="text-text-muted">
                {service.description}
            </p>
        </motion.div>
    );
};

export default ServiceCard;

