                            <img
                                src="/landscaping 2.jpeg"
                                alt="Our Signature Stone Work"
                                className="about-img shadow-2xl"
                            />
                            {/* Decorative tag */}
                            <div style={{ position: 'absolute', bottom: '0', right: '0', background: 'var(--primary)', color: 'white', padding: '1rem 2rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.2em' }}>
                                Signature Stone
                            </div>
                        </motion.div>
                    </div>
                </div>
            </section>

        </div>
    );
};

export default About;

