import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Check, ShieldCheck, Droplets, Sun, Sparkles } from 'lucide-react';
import NextPage from '../components/NextPage';

const Blog = () => {
    const [selectedPost, setSelectedPost] = useState(null);

    useEffect(() => {
        document.title = "Landscape Blog | Stonehouse Landscape";
    }, []);

    const posts = [
        {
            id: 1,
            title: "Choosing the Right Stone for Your Path",
            excerpt: "Selecting the perfect stone for your pathway involves balancing aesthetics with durability. Bangalore Stone offers a rustic charm, while Tandur provides a sleek, modern finish.",
            details: "When designing a pathway, consider the 'Stepability' and 'Slip Resistance'. Natural stones like Tandur are excellent for high-traffic areas due to their dense structure. For a more organic, rugged look, Bangalore Stone irregular slabs create a timeless woodland feel. Always ensure a 1-2% slope for drainage.",
            maintenanceTags: ["Periodic Sealing", "Slope Check", "Moss Removal"],
            image: "/landscaping 2.jpeg"
        },
        {
            id: 2,
            title: "Essential Natural Stone Maintenance",
            excerpt: "Natural stone is an investment in your property. To keep your pathways and cladding looking pristine, regular care is essential, especially in tropical climates.",
            details: "Maintenance Tips: 1. Cleaning: Use only pH-neutral cleaners; avoid acidic solutions that can etch stones like limestone. 2. Sealing: Apply a high-quality penetrative sealer every 12-24 months. 3. Debris: Sweep regularly to prevent organic matter from staining the stone surface during monsoon seasons.",
            maintenanceTags: ["pH Neutral Cleaning", "UV Protection", "Annual Sealing"],
            image: "/stone cladding.jpeg"
        },
        {
            id: 3,
            title: "Sustainable Gardening Practices",
            excerpt: "Sustainability involves soil management, water conservation through smart irrigation, and choosing native flora that thrives with minimal chemical intervention.",
            details: "To build a sustainable landscape: 1. Mulching: Use organic mulch to retain soil moisture and suppress weeds. 2. Native Plants: They require less water and are naturally resistant to local pests. 3. Smart Watering: Install drip irrigation systems to deliver water directly to the roots, reducing evaporation.",
            maintenanceTags: ["Composting", "Drip Irrigation", "Native Planting"],
            image: "/artificial grass.jpeg"
        },
        {
            id: 4,
            title: "2024 Hardscaping Trends",
            excerpt: "Geometric patterns, mixed-material patios, and functional outdoor seating are defining this year's landscape architecture scene.",
            details: "The biggest trend for 2024 is 'Indoor-Outdoor Fluidity'. Using the same stone cladding for internal walls and external boundary walls creates a sense of vastness. Mixed texturesΓÇölike combining smooth Tandur pavers with rough Kadappa bordersΓÇöadd architectural depth to modern homes.",
            maintenanceTags: ["Joint Sanding", "Stain Prevention", "Structural Check"],
            image: "/landscaping 1.jpeg"
        },
        {
            id: 5,
            title: "Landscape Lighting Basics",
            excerpt: "Transform your landscape into a nocturnal paradise. Layered lighting highlights architectural features and creates incredible depth after sunset.",
            details: "Lighting Strategy: 1. Uplighting: Place lights at the base of trees or stone walls to create dramatic silhouettes. 2. Path Lighting: Use low-profile fixtures to guide guests safely. 3. Layering: Combine ambient, task, and accent lighting for a balanced, high-end resort feel at home.",
