            image: "/pebbles.jpeg"
        }
    ];

    const openModal = (post) => {
        setSelectedPost(post);
        document.body.style.overflow = 'hidden';
    };

    const closeModal = () => {
        setSelectedPost(null);
        document.body.style.overflow = 'unset';
    };

    return (
        <div className="blog-page">
            <section className="section-cream pt-40">
                <div className="container">
                    <div className="section-title">
                        <h1 className="text-7xl font-black mb-6">Our <span className="text-primary">Blog.</span></h1>
                        <p className="text-xl text-muted">Insights and tips for a beautiful outdoor life.</p>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(400px, 1fr))', gap: '3rem' }}>
