                                <p className="text-muted mb-8 leading-relaxed line-clamp-3">{post.excerpt}</p>
                                <button
                                    onClick={() => openModal(post)}
                                    className="cta-btn cta-primary"
                                    style={{ padding: '0.8rem 2rem', marginTop: 'auto', alignSelf: 'flex-start' }}
                                >
                                    Read More
                                </button>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </section>

            {/* BLOG ARTICLE MODAL */}
            <AnimatePresence>
                {selectedPost && (
                    <div className="modal-overlay" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2000, position: 'fixed', inset: 0 }}>
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="modal-content shadow-2xl"
                            style={{
                                width: '95%',
                                maxWidth: '1000px',
                                maxHeight: '90vh',
                                display: 'flex',
                                flexDirection: 'column',
                                overflow: 'hidden',
                                border: 'none'
                            }}
                        >
                            <button
                                onClick={closeModal}
                                style={{ position: 'absolute', top: '1.5rem', right: '1.5rem', background: 'white', border: 'none', borderRadius: '50%', width: '40px', height: '40px', cursor: 'pointer', zIndex: 10, boxShadow: '0 5px 20px rgba(0,0,0,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                            >
                                <X size={20} />
                            </button>

                            <div style={{ height: '300px', width: '100%' }}>
                                <img src={selectedPost.image} alt={selectedPost.title} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            </div>

                            <div style={{ padding: '4rem', overflowY: 'auto', background: 'var(--bg-cream)' }}>
                                <span className="text-primary font-black uppercase text-xs tracking-widest mb-4 block">Landscape Insights</span>
                                <h3 className="text-4xl font-black mb-8 leading-tight">{selectedPost.title}</h3>

                                <div className="text-lg text-black leading-relaxed mb-10" style={{ whiteSpace: 'pre-line' }}>
                                    {selectedPost.details}
                                </div>

                                <div style={{ borderTop: '1px solid rgba(0,0,0,0.1)', pt: '3rem', mt: '3rem' }}>
                                    <h4 className="text-xs uppercase font-black tracking-widest mb-6 opacity-40">Pro Maintenance Tips</h4>
                                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '15px' }}>
                                        {selectedPost.maintenanceTags.map(tag => (
                                            <div key={tag} className="flex items-center gap-2 text-sm font-bold bg-white px-4 py-2 border border-primary/20">
                                                <Sparkles size={14} className="text-primary" /> {tag}
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                <button onClick={closeModal} className="cta-btn cta-primary" style={{ width: '100%', padding: '1.5rem', marginTop: '4rem' }}>
                                    Close Article
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default Blog;

